INSERT INTO page_lang VALUES(205,'all','webp.intro','是 Google 推出的现代图片格式，具有高压缩率和优良画质，支持有损和无损压缩、透明通道和动画。相比 JPG/PNG，WebP 格式能显著减小图片体积，加快网页加载速度，提升网站性能和 SEO 表现。主流浏览器均已支持 WebP，推荐在网站中优先使用。','zh','2025-08-10 05:13:19','2025-08-10 05:13:19');
